#include "nearly_incompressible_mooney_rivlin.hpp"

double NearlyIncompressibleMooneyRivlin::strain_energy(MaterialData * md,
                                                     const arma::mat & E) const
{
  // Right Cauchy-Green deformation tensor
  arma::mat C = 2.0*E + arma::eye<arma::mat>(3,3);
  
  // Jacobian
  double J = sqrt(arma::det(C));

  // Isochoric right Cauchy-Green deformation tensor
  arma::mat Cbar = pow(J,(-2.0/3.0)) * C;
  
  // Invariant 1 - trace of isochoric right Cauchy-Green tensor
  double I1bar = trace(Cbar);

  // Invariant 2
  double I2bar = 0.5 * (I1bar*I1bar) - contract(Cbar,Cbar);

  return c1*(I1bar-3.0) + c2*(I2bar-3.0) + (K/2.0)*log(J)*log(J);
}

